campaign_collect_after_snapshot.cmd:
set -o pipefail
{
  echo "== DATE =="; date -Is;
  echo "== HOSTNAME =="; hostname -f 2>/dev/null || hostname;
  echo "== UPTIME =="; uptime;
  echo "== KERNEL =="; uname -a;
  echo "== FAILED SYSTEMD UNITS ==";
  systemctl --failed --no-pager 2>/dev/null || true;
  echo "== REBOOT REQUIRED ==";
  test -f /var/run/reboot-required && echo "yes" || echo "no";
} | sed 's/\r$//'

campaign_collect_before_snapshot.cmd:
set -o pipefail
{
  echo "== DATE =="; date -Is;
  echo "== HOSTNAME =="; hostname -f 2>/dev/null || hostname;
  echo "== UPTIME =="; uptime;
  echo "== KERNEL =="; uname -a;
  echo "== OS =="; (cat /etc/os-release 2>/dev/null || true);
  echo "== DISK =="; df -h;
  echo "== MEM =="; free -h 2>/dev/null || true;
  echo "== FAILED SYSTEMD UNITS ==";
  systemctl --failed --no-pager 2>/dev/null || true;
} | sed 's/\r$//'
